# ================= END V204 FRONTEND OPERATION ISOLATION =================

# ================= V205 01 SECOND-LEVEL FOREGROUND TRANSACTION =================
# Direct-overwrite version. UI-neutral: no pages/CSS/theme/table rendering changes.
# Purpose:
# - 01 Start / Continue / Finish buttons must not call the old wrapper chain that
#   rebuilds final view, scans authority, or schedules heavy GitHub work in the foreground.
# - Foreground uses SQLite as the immediate transaction source, with hard-delete
#   filtering and LOGRECOVERY isolation for display safety.
# - Slow authority/GitHub publication is represented by a tiny queue record only;
#   it is intentionally not executed inside the user's click.

try:
    import time as _v205_time
except Exception:  # pragma: no cover
    _v205_time = None

_V205_READ_CACHE: dict[tuple, tuple[float, pd.DataFrame | dict | None]] = {}
_V205_READ_CACHE_TTL_SEC = 3.0


def _v205_now() -> str:
    try:
        return now_text()
    except Exception:
        return datetime.now().strftime("%Y-%m-%d %H:%M:%S")


def _v205_today() -> str:
    try:
        return today_text()
    except Exception:
        return datetime.now().strftime("%Y-%m-%d")


def _v205_conn() -> sqlite3.Connection:
    try:
        DB_PATH.parent.mkdir(parents=True, exist_ok=True)
    except Exception:
        pass
    conn = sqlite3.connect(str(DB_PATH), timeout=8, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    try:
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA synchronous=NORMAL")
        conn.execute("PRAGMA busy_timeout=8000")
    except Exception:
        pass
    return conn


def _v205_cache_key(sql: str, params: tuple) -> tuple:
    return ("v205", " ".join(str(sql or "").split()), tuple(params or ()))


def _v205_cache_get(key: tuple):
    if _v205_time is None:
        return None
    item = _V205_READ_CACHE.get(key)
    if not item:
        return None
    if _v205_time.time() - item[0] > _V205_READ_CACHE_TTL_SEC:
        _V205_READ_CACHE.pop(key, None)
        return None
    val = item[1]
    if isinstance(val, pd.DataFrame):
        return val.copy()
    if isinstance(val, dict):
        return dict(val)
    return val


def _v205_cache_put(key: tuple, val) -> None:
    if _v205_time is None:
        return
    if len(_V205_READ_CACHE) > 80:
        try:
            _V205_READ_CACHE.clear()
        except Exception:
            pass
    try:
        _V205_READ_CACHE[key] = (_v205_time.time(), val.copy() if isinstance(val, pd.DataFrame) else (dict(val) if isinstance(val, dict) else val))
    except Exception:
        pass


def _v205_clear_caches() -> None:
    try:
        _V205_READ_CACHE.clear()
    except Exception:
        pass
    try:
        clear_query_cache()
    except Exception:
        pass
    try:
        if "clear_today_records_fast_cache" in globals() and callable(clear_today_records_fast_cache):
            clear_today_records_fast_cache()
    except Exception:
        pass


def _v205_query_df(sql: str, params: tuple = ()) -> pd.DataFrame:
    key = _v205_cache_key(sql, params)
    hit = _v205_cache_get(key)
    if isinstance(hit, pd.DataFrame):
        return hit
    try:
        with _v205_conn() as conn:
            df = pd.read_sql_query(sql, conn, params=params)
    except Exception:
        df = pd.DataFrame()
    df = _v205_filter_visible_rows(df)
    _v205_cache_put(key, df)
    return df.copy()


def _v205_query_one(sql: str, params: tuple = ()) -> dict | None:
    key = _v205_cache_key(sql, params)
    hit = _v205_cache_get(key)
    if isinstance(hit, dict) or hit is None:
        return dict(hit) if isinstance(hit, dict) else None
    try:
        with _v205_conn() as conn:
            row = conn.execute(sql, params).fetchone()
            out = dict(row) if row else None
    except Exception:
        out = None
    if out:
        df = _v205_filter_visible_rows(pd.DataFrame([out]))
        out = dict(df.iloc[0].to_dict()) if isinstance(df, pd.DataFrame) and not df.empty else None
    _v205_cache_put(key, out)
    return dict(out) if isinstance(out, dict) else None


def _v205_filter_visible_rows(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame() if df is None else df
    out = df.copy()
    try:
        from services.time_record_hard_delete_guard_service import filter_deleted_rows
        out = filter_deleted_rows(out)
    except Exception:
        pass
    try:
        # Unresolved LOG-only recovery rows must not enter ordinary 01/02 foreground display.
        if not out.empty:
            src = out.get("source", pd.Series([""] * len(out))).astype(str).str.upper()
            rk = out.get("record_key", pd.Series([""] * len(out))).astype(str).str.upper()
            status = out.get("status", pd.Series([""] * len(out))).astype(str)
            end_ts = out.get("end_timestamp", pd.Series([""] * len(out))).astype(str).str.strip()
            unresolved_recovery = (
                src.str.contains("LOGRECOVERY|V164B_LOG_ONLY_RECOVERY|LOG_ONLY_RECOVERY|PENDING_RECOVERY", regex=True, na=False)
                | rk.str.startswith("LOGRECOVERY|")
                | status.str.contains("待人工", na=False)
            ) & (end_ts.isin(["", "None", "nan", "NaT"]))
            out = out.loc[~unresolved_recovery].copy()
    except Exception:
        pass
    return out.reset_index(drop=True)


def _v205_is_active_sql() -> str:
    return """
        (end_timestamp IS NULL OR TRIM(COALESCE(end_timestamp,''))='' OR LOWER(TRIM(COALESCE(end_timestamp,''))) IN ('none','nan','nat','null'))
        AND (COALESCE(status,'')='' OR status='作業中')
    """


def _v205_direct_log(action_type: str, message: str, target_id: str | int | None = "", detail: str = "", level: str = "INFO") -> None:
    try:
        user = "SYSTEM"
        try:
            import streamlit as st  # type: ignore
            ss = getattr(st, "session_state", {})
            user = str(ss.get("auth_username") or ss.get("username") or ss.get("current_username") or "SYSTEM")
        except Exception:
            pass
        with _v205_conn() as conn:
            conn.execute(
                """
                INSERT INTO system_logs(log_time,user_name,action_type,target_table,target_id,message,detail,level)
                VALUES(?,?,?,?,?,?,?,?)
                """,
                (_v205_now(), user, str(action_type), "time_records", str(target_id or ""), str(message or ""), str(detail or ""), str(level or "INFO")),
            )
            conn.commit()
    except Exception:
        try:
            write_log(action_type, message, "time_records", str(target_id or ""), detail=detail, level=level)
        except Exception:
            pass


def _v205_enqueue(reason: str, payload: dict | None = None) -> None:
    try:
        from services.frontend_operation_isolation_service import enqueue_job
        enqueue_job("v205_time_record_background_publish", payload or {}, reason=reason)
    except Exception:
        pass


def _v205_after_local_mutation(reason: str, payload: dict | None = None) -> None:
    _v205_clear_caches()
    _v205_enqueue(reason, payload or {})
    try:
        mark_data_changed(f"{reason}：本機交易完成，待背景備份。", reason)
    except Exception:
        pass


def load_records(start_date: str | None = None, end_date: str | None = None, employee_id: str | None = None, work_order: str | None = None) -> pd.DataFrame:  # type: ignore[override]
    sql = "SELECT * FROM time_records WHERE 1=1"
    params: list = []
    if start_date:
        sql += " AND start_date>=?"
        params.append(str(start_date))
    if end_date:
        sql += " AND start_date<=?"
        params.append(str(end_date))
    if employee_id:
        sql += " AND employee_id=?"
        params.append(str(employee_id).strip())
    if work_order:
        sql += " AND work_order=?"
        params.append(str(work_order).strip())
    sql += " ORDER BY id DESC"
    return _v205_query_df(sql, tuple(params))


def today_records(include_finished: bool = True, unfinished_only: bool = False) -> pd.DataFrame:  # type: ignore[override]
    sql = "SELECT * FROM time_records WHERE start_date>=?"
    params: list = [_v205_today()]
    if unfinished_only or not include_finished:
        sql += " AND " + _v205_is_active_sql()
    sql += " ORDER BY id DESC"
    return _v205_query_df(sql, tuple(params))


def get_active_records(employee_id: str | None = None, process_name: str | None = None, start_date: str | None = None, employee_name: str | None = None) -> pd.DataFrame:  # type: ignore[override]
    sql = "SELECT * FROM time_records WHERE " + _v205_is_active_sql()
    params: list = []
    if employee_id:
        sql += " AND employee_id=?"
        params.append(str(employee_id).strip())
    if employee_name:
        sql += " AND COALESCE(employee_name,'')=?"
        params.append(str(employee_name).strip())
    if process_name:
        sql += " AND process_name=?"
        params.append(str(process_name).strip())
    if start_date:
        sql += " AND start_date=?"
        params.append(str(start_date).strip())
    sql += " ORDER BY employee_id, employee_name, process_name, start_timestamp, id"
    return _v205_query_df(sql, tuple(params))


def get_active_record(employee_id: str, employee_name: str | None = None) -> dict | None:  # type: ignore[override]
    sql = "SELECT * FROM time_records WHERE " + _v205_is_active_sql() + " AND employee_id=?"
    params: list = [str(employee_id).strip()]
    if employee_name:
        sql += " AND COALESCE(employee_name,'')=?"
        params.append(str(employee_name).strip())
    sql += " ORDER BY id DESC LIMIT 1"
    return _v205_query_one(sql, tuple(params))


def get_active_same_work(employee_id: str, work_order: str, process_name: str, start_date: str | None = None, employee_name: str | None = None) -> dict | None:  # type: ignore[override]
    sd = str(start_date or _v205_today())
    sql = "SELECT * FROM time_records WHERE " + _v205_is_active_sql() + " AND employee_id=? AND work_order=? AND process_name=? AND start_date=?"
    params: list = [str(employee_id).strip(), str(work_order).strip(), str(process_name).strip(), sd]
    if employee_name:
        sql += " AND COALESCE(employee_name,'')=?"
        params.append(str(employee_name).strip())
    sql += " ORDER BY id DESC LIMIT 1"
    return _v205_query_one(sql, tuple(params))


def get_conflicting_active_records(employee_id: str, process_name: str, start_date: str | None = None, employee_name: str | None = None) -> pd.DataFrame:  # type: ignore[override]
    sd = str(start_date or _v205_today())
    sql = "SELECT * FROM time_records WHERE " + _v205_is_active_sql() + " AND employee_id=?"
    params: list = [str(employee_id).strip()]
    if employee_name:
        sql += " AND COALESCE(employee_name,'')=?"
        params.append(str(employee_name).strip())
    sql += " AND (COALESCE(process_name,'')<>? OR COALESCE(start_date,'')<>?) ORDER BY id"
    params.extend([str(process_name).strip(), sd])
    return _v205_query_df(sql, tuple(params))


def get_active_group(record_id: int) -> pd.DataFrame:  # type: ignore[override]
    rec = _v205_query_one("SELECT * FROM time_records WHERE id=?", (int(record_id),))
    if not rec:
        return pd.DataFrame()
    return get_active_records(
        employee_id=str(rec.get("employee_id") or ""),
        employee_name=str(rec.get("employee_name") or ""),
        process_name=str(rec.get("process_name") or ""),
        start_date=str(rec.get("start_date") or ""),
    )


def _v205_sqlite_insert_record(employee: dict, work_order: dict, process_name: str, remark: str = "") -> int:
    now = _v205_now()
    start_date, start_time = split_timestamp(now)
    employee_id = str((employee or {}).get("employee_id") or "").strip()
    employee_name = str((employee or {}).get("employee_name") or "").strip()
    wo_no = str((work_order or {}).get("work_order") or "").strip()
    process = str(process_name or "").strip()
    if not employee_id or not wo_no or not process:
        raise ValueError("工號、製令、工段名稱不可空白。")
    record_key = make_record_key(employee_id, wo_no, process, now)
    group_key = f"{employee_id}|{process}|{start_date}"
    with _v205_conn() as conn:
        cur = conn.execute(
            """
            INSERT INTO time_records(
                record_key, status, work_order, part_no, type_name, process_name,
                employee_id, employee_name, start_action, start_timestamp,
                remark, start_date, start_time, assembly_location,
                group_key, is_group_work, source, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                record_key, "作業中", wo_no,
                (work_order or {}).get("part_no", ""),
                (work_order or {}).get("type_name", ""),
                process, employee_id, employee_name, "開始", now, remark,
                start_date, start_time, (work_order or {}).get("assembly_location", ""),
                group_key, 0, "streamlit_v205_fast", now, now,
            ),
        )
        rid = int(cur.lastrowid or 0)
        count_row = conn.execute(
            """
            SELECT COUNT(*) AS c FROM time_records
            WHERE employee_id=? AND COALESCE(employee_name,'')=? AND process_name=? AND start_date=?
              AND (end_timestamp IS NULL OR TRIM(COALESCE(end_timestamp,''))='')
            """,
            (employee_id, employee_name, process, start_date),
        ).fetchone()
        if int((count_row or {}).get("c", 0) if isinstance(count_row, dict) else (count_row["c"] if count_row else 0)) > 1:
            conn.execute(
                """
                UPDATE time_records SET is_group_work=1, group_key=?, updated_at=?
                WHERE employee_id=? AND COALESCE(employee_name,'')=? AND process_name=? AND start_date=?
                  AND (end_timestamp IS NULL OR TRIM(COALESCE(end_timestamp,''))='')
                """,
                (group_key, now, employee_id, employee_name, process, start_date),
            )
        conn.commit()
    _v205_direct_log("START_WORK", f"{employee_name} 開始 {wo_no} / {process}", rid, detail="V205_FAST_START")
    return rid


def start_work(employee: dict, work_order: dict, process_name: str, remark: str = "", auto_pause_old: bool = True) -> int:  # type: ignore[override]
    now = _v205_now()
    start_date, _ = split_timestamp(now)
    employee_id = str((employee or {}).get("employee_id") or "").strip()
    employee_name = str((employee or {}).get("employee_name") or "").strip()
    wo_no = str((work_order or {}).get("work_order") or "").strip()
    process = str(process_name or "").strip()
    if not employee_id or not wo_no or not process:
        raise ValueError("工號、製令、工段名稱不可空白。")
    duplicate = get_active_same_work(employee_id, wo_no, process, start_date, employee_name=employee_name)
    if duplicate:
        raise ValueError(f"此人員已有相同製令與工段正在計時，禁止重複紀錄：{wo_no} / {process}")
    conflicts = get_conflicting_active_records(employee_id, process, start_date, employee_name=employee_name)
    if isinstance(conflicts, pd.DataFrame) and not conflicts.empty:
        if not auto_pause_old:
            raise ValueError("此人員已有不同工段正在計時，請先確認暫停前一筆作業後再開始新紀錄。")
        for _, rr in conflicts.iterrows():
            try:
                finish_work(int(rr.get("id")), "暫停", "系統自動暫停：同一人員切換不同工段或不同日期作業", finish_parallel_group=True)
            except Exception:
                pass
    rid = _v205_sqlite_insert_record(employee, work_order, process, remark)
    _v205_after_local_mutation("V205_FAST_START_WORK", {"id": rid, "employee_id": employee_id, "work_order": wo_no, "process_name": process})
    return int(rid)


def finish_work(record_id: int, end_action: str, remark: str = "", finish_parallel_group: bool = True) -> int:  # type: ignore[override]
    rid0 = int(record_id)
    with _v205_conn() as conn:
        rec_row = conn.execute("SELECT * FROM time_records WHERE id=?", (rid0,)).fetchone()
        if not rec_row:
            raise ValueError("找不到工時紀錄；此筆可能已刪除、已結束，或畫面資料尚未重新整理。")
        rec = dict(rec_row)
        if str(rec.get("end_timestamp") or "").strip():
            return 0
        now = _v205_now()
        end_date, end_time = split_timestamp(now)
        status = end_action if end_action in ("下班", "暫停", "完工") else "已結束"
        if finish_parallel_group:
            rows = conn.execute(
                """
                SELECT * FROM time_records
                WHERE employee_id=? AND COALESCE(employee_name,'')=? AND process_name=? AND start_date=?
                  AND (end_timestamp IS NULL OR TRIM(COALESCE(end_timestamp,''))='')
                ORDER BY id
                """,
                (rec.get("employee_id"), rec.get("employee_name") or "", rec.get("process_name"), rec.get("start_date")),
            ).fetchall()
        else:
            rows = [rec_row]
        group = [dict(r) for r in rows] or [rec]
        group_ids = [int(x.get("id")) for x in group if x.get("id") is not None]
        starts = [str(x.get("start_timestamp") or "") for x in group if str(x.get("start_timestamp") or "").strip()]
        earliest_start = min(starts) if starts else str(rec.get("start_timestamp") or now)
        try:
            total_hours = float(calculate_work_hours(earliest_start, now) or 0)
        except Exception:
            total_hours = 0.0
        avg_hours = round(total_hours / max(len(group_ids), 1), 2)
        is_group = 1 if len(group_ids) > 1 else int(rec.get("is_group_work") or 0)
        group_key = rec.get("group_key") or f"{rec.get('employee_id')}|{rec.get('process_name')}|{rec.get('start_date')}"
        for rid in group_ids:
            old_row = conn.execute("SELECT remark FROM time_records WHERE id=?", (rid,)).fetchone()
            old_remark = str((old_row["remark"] if old_row and "remark" in old_row.keys() else "") or "")
            append = str(remark or "")
            if len(group_ids) > 1:
                try:
                    summary = _v138_parallel_summary_text(len(group_ids), total_hours, avg_hours)
                except Exception:
                    summary = f"同步作業平均分配：{len(group_ids)}筆，平均工時={avg_hours}"
                append = (append + "；" if append else "") + summary
            new_remark = old_remark + ("；" if old_remark and append else "") + append if append else old_remark
            conn.execute(
                """
                UPDATE time_records
                SET status=?, end_action=?, end_timestamp=?, end_date=?, end_time=?,
                    work_hours=?, remark=?, group_key=?, is_group_work=?, updated_at=?
                WHERE id=? AND (end_timestamp IS NULL OR TRIM(COALESCE(end_timestamp,''))='')
                """,
                (status, end_action, now, end_date, end_time, avg_hours, new_remark, group_key, is_group, now, rid),
            )
        conn.commit()
    _v205_direct_log(
        "END_WORK_GROUP" if len(group_ids) > 1 else "END_WORK",
        f"結束工時紀錄 #{rid0}，同步結束={len(group_ids)}筆，狀態={status}",
        rid0,
        detail=",".join(str(x) for x in group_ids) + ";V205_FAST_FINISH",
    )
    _v205_after_local_mutation("V205_FAST_FINISH_WORK", {"id": rid0, "group_ids": group_ids, "status": status})
    return int(len(group_ids))


def audit_v205_01_second_level_operation() -> dict:
    return {
        "version": "V205",
        "ui_changed": False,
        "pages_changed": False,
        "theme_service_changed": False,
        "css_changed": False,
        "foreground_start_work": "direct_sqlite_single_transaction",
        "foreground_finish_work": "direct_sqlite_single_transaction",
        "final_view_rebuild_in_foreground": False,
        "github_publish_in_foreground": False,
        "background_queue_only": True,
    }

