# ================= END V210 CANONICAL DISPLAY + SAFE SQLITE DELTA =================

# ================= V212 RESTORE PER-ROW DURABLE SAVE + AUTHORITY ID SEQUENCE GUARD｜2026-05-29 =================
# Root cause fixed:
# - V205 fast start/finish wrote SQLite immediately but bypassed the old per-row durable save chain
#   (01/02 authority JSON + row shard + event journal). A newly started row could appear from SQLite,
#   then disappear when display reconciled against authority JSON that did not yet contain that row.
# - When SQLite had only a partial legacy cache, AUTOINCREMENT could also allocate an id that already
#   existed in 01/02 authority.  This made display/finish-by-id ambiguous.
#
# This section preserves the V205 fast SQLite transaction, but before Start aligns SQLite AUTOINCREMENT
# with max authority id, and after Start/Finish immediately writes the changed row(s) to the local
# per-row durable layers.  It does not change UI/CSS/theme/table/buttons and does not upload to GitHub
# in the foreground.
try:
    _v212_prev_start_work = start_work
except Exception:  # pragma: no cover
    _v212_prev_start_work = None
try:
    _v212_prev_finish_work = finish_work
except Exception:  # pragma: no cover
    _v212_prev_finish_work = None
try:
    _v212_prev_save_time_records = save_time_records
except Exception:  # pragma: no cover
    _v212_prev_save_time_records = None


def _v212_clean_ids(ids) -> list[int]:
    out: list[int] = []
    for x in ids or []:
        try:
            i = int(float(str(x).strip()))
            if i > 0 and i not in out:
                out.append(i)
        except Exception:
            continue
    return out


def _v212_authority_max_id() -> int:
    max_id = 0
    try:
        from services.permanent_authority_service import df_from_table as _pa_df_from_table  # type: ignore
        for module_key in ("01_time_records", "02_history"):
            try:
                df = _pa_df_from_table(module_key, "time_records")
                if isinstance(df, pd.DataFrame) and not df.empty and "id" in df.columns:
                    val = pd.to_numeric(df["id"], errors="coerce").max()
                    if pd.notna(val):
                        max_id = max(max_id, int(float(val)))
            except Exception:
                continue
    except Exception:
        pass
    return int(max_id or 0)


def _v212_sync_sqlite_sequence_with_authority(reason: str = "v212_before_start") -> int:
    """Prevent new SQLite ids from colliding with 01/02 authority ids when SQLite cache is partial."""
    auth_max = _v212_authority_max_id()
    if auth_max <= 0:
        return 0
    try:
        with _v205_conn() as conn:
            exists = conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='time_records'").fetchone()
            if not exists:
                return 0
            try:
                sqlite_max_row = conn.execute("SELECT COALESCE(MAX(id),0) AS m FROM time_records").fetchone()
                sqlite_max = int(sqlite_max_row["m"] if sqlite_max_row else 0)
            except Exception:
                sqlite_max = 0
            # AUTOINCREMENT uses sqlite_sequence.  Set it to authority max when the local cache is behind.
            if sqlite_max < auth_max:
                try:
                    seq_row = conn.execute("SELECT seq FROM sqlite_sequence WHERE name='time_records'").fetchone()
                    if seq_row is None:
                        conn.execute("INSERT INTO sqlite_sequence(name, seq) VALUES('time_records', ?)", (auth_max,))
                    else:
                        conn.execute("UPDATE sqlite_sequence SET seq=? WHERE name='time_records' AND seq<?", (auth_max, auth_max))
                    conn.commit()
                    try:
                        _v205_direct_log("V212_SQLITE_SEQUENCE_GUARD", f"SQLite 工時 ID 序號已對齊權威檔 max_id={auth_max}，避免新增紀錄 ID 撞號。", detail=reason, level="INFO")
                    except Exception:
                        pass
                    return auth_max
                except Exception:
                    return 0
    except Exception:
        return 0
    return 0


def _v212_query_sqlite_rows_by_ids(ids) -> pd.DataFrame:
    clean = _v212_clean_ids(ids)
    if not clean:
        return pd.DataFrame()
    try:
        placeholders = ",".join(["?"] * len(clean))
        with _v205_conn() as conn:
            df = pd.read_sql_query(
                f"SELECT * FROM time_records WHERE id IN ({placeholders}) ORDER BY id",
                conn,
                params=tuple(clean),
            )
        try:
            df = _v205_filter_visible_rows(df) if "_v205_filter_visible_rows" in globals() else df
        except Exception:
            pass
        return df.reset_index(drop=True) if isinstance(df, pd.DataFrame) else pd.DataFrame()
    except Exception:
        return pd.DataFrame()


def _v212_sqlite_active_group_ids(record_id: int, finish_parallel_group: bool = True) -> list[int]:
    rid0 = _v212_clean_ids([record_id])
    if not rid0:
        return []
    if not finish_parallel_group:
        return rid0
    try:
        with _v205_conn() as conn:
            rec = conn.execute("SELECT * FROM time_records WHERE id=?", (rid0[0],)).fetchone()
            if not rec:
                return rid0
            row = dict(rec)
            rows = conn.execute(
                """
                SELECT id FROM time_records
                WHERE employee_id=? AND COALESCE(employee_name,'')=? AND process_name=? AND start_date=?
                  AND (end_timestamp IS NULL OR TRIM(COALESCE(end_timestamp,''))='' OR LOWER(TRIM(COALESCE(end_timestamp,''))) IN ('none','nan','nat','null'))
                  AND (COALESCE(status,'')='' OR status='作業中')
                ORDER BY id
                """,
                (
                    row.get("employee_id"),
                    row.get("employee_name") or "",
                    row.get("process_name"),
                    row.get("start_date"),
                ),
            ).fetchall()
        ids = [int(r["id"]) for r in rows if r and r["id"] is not None]
        if rid0[0] not in ids:
            ids.append(rid0[0])
        return _v212_clean_ids(ids)
    except Exception:
        return rid0


def _v212_event_type_for_end_action(end_action: str) -> str:
    action = str(end_action or "").strip()
    if action == "暫停":
        return "PAUSE_WORK"
    if action == "下班":
        return "OFF_DUTY"
    if action == "完工":
        return "FINISH_WORK"
    return "END_WORK"


def _v212_fallback_authority_upsert(rows_df: pd.DataFrame, reason: str) -> int:
    """Minimal local-only authority upsert if V176 durable layer is unavailable."""
    if rows_df is None or not isinstance(rows_df, pd.DataFrame) or rows_df.empty:
        return 0
    try:
        from services.permanent_authority_service import df_from_table as _pa_df_from_table, save_authority as _pa_save_authority  # type: ignore
    except Exception:
        return 0
    try:
        changed = rows_df.copy().where(pd.notna(rows_df), "")
        changed_rows = [dict(r) for _, r in changed.iterrows()]
    except Exception:
        return 0

    def _key(row: dict) -> str:
        try:
            rk = str(row.get("record_key") or "").strip()
            if rk:
                return "rk:" + rk
            rid = str(row.get("id") or "").strip()
            if rid:
                return "id:" + str(int(float(rid)))
        except Exception:
            pass
        try:
            return "biz:" + "|".join([
                str(row.get("employee_id") or "").strip(),
                str(row.get("employee_name") or "").strip(),
                str(row.get("work_order") or "").strip(),
                str(row.get("process_name") or "").strip(),
                str(row.get("start_timestamp") or "").strip(),
            ])
        except Exception:
            return ""

    saved = 0
    for module_key in ("01_time_records", "02_history"):
        try:
            base = _pa_df_from_table(module_key, "time_records")
            base = base.copy().where(pd.notna(base), "") if isinstance(base, pd.DataFrame) and not base.empty else pd.DataFrame()
            row_map: dict[str, dict] = {}
            order: list[str] = []
            if isinstance(base, pd.DataFrame) and not base.empty:
                for _, rr in base.iterrows():
                    d = dict(rr)
                    k = _key(d)
                    if not k:
                        continue
                    if k not in row_map:
                        order.append(k)
                    row_map[k] = d
            for d in changed_rows:
                k = _key(d)
                if not k:
                    continue
                if k not in row_map:
                    order.append(k)
                old = dict(row_map.get(k) or {})
                old.update(d)
                row_map[k] = old
            merged = [row_map[k] for k in order if k in row_map]
            _pa_save_authority(module_key, records={"time_records": merged}, reason=f"{reason}_{module_key}", github=False)
            saved = max(saved, len(merged))
        except Exception as exc:
            try:
                _v205_direct_log("V212_AUTHORITY_UPSERT_WARN", f"V212 權威檔逐筆 upsert 失敗 {module_key}: {exc}", detail=reason, level="WARN")
            except Exception:
                pass
    return int(saved or 0)


def _v212_write_row_durable_layers(rows_df: pd.DataFrame, reason: str, event_type: str, extra: dict | None = None) -> int:
    """Immediate per-row local save for Start/Finish without foreground GitHub upload."""
    if rows_df is None or not isinstance(rows_df, pd.DataFrame) or rows_df.empty:
        return 0
    saved = 0
    try:
        if "_v176_write_durable_layers" in globals() and callable(_v176_write_durable_layers):
            _v176_write_durable_layers(rows_df, reason, event_type, extra=extra or {})
            saved = int(len(rows_df))
        else:
            saved = _v212_fallback_authority_upsert(rows_df, reason)
            try:
                from services.time_record_event_journal_service import append_time_record_event  # type: ignore
                append_time_record_event(event_type, rows_df, reason=reason, payload_extra=extra or {}, schedule_upload=True)
            except Exception:
                pass
    except Exception as exc:
        try:
            _v205_direct_log("V212_ROW_SAVE_WARN", f"V212 儲存工時逐筆紀錄失敗：{exc}", detail=reason, level="WARN")
        except Exception:
            pass
        return 0
    try:
        _v205_clear_caches()
    except Exception:
        pass
    try:
        _v205_direct_log(
            "V212_ROW_SAVE_TIME_RECORD",
            f"儲存工時逐筆紀錄：{event_type}，{len(rows_df)} 筆已寫入 01/02 權威檔與事件紀錄。",
            target_id=",".join([str(x) for x in rows_df.get("id", pd.Series([], dtype=str)).tolist()]) if "id" in rows_df.columns else "",
            detail=reason,
            level="INFO",
        )
    except Exception:
        pass
    return int(saved or len(rows_df))


def start_work(employee: dict, work_order: dict, process_name: str, remark: str = "", auto_pause_old: bool = True) -> int:  # type: ignore[override]
    """V212: keep V205 fast SQLite start, prevent id collision, then restore immediate per-row durable save."""
    if not callable(_v212_prev_start_work):
        raise RuntimeError("start_work core implementation is unavailable")
    _v212_sync_sqlite_sequence_with_authority("start_work_v212_before_fast_insert")
    rid = int(_v212_prev_start_work(employee, work_order, process_name, remark, auto_pause_old=auto_pause_old) or 0)
    if rid:
        rows_df = _v212_query_sqlite_rows_by_ids([rid])
        _v212_write_row_durable_layers(
            rows_df,
            "start_work_v212_restore_per_row_save",
            "START_WORK",
            extra={"employee": employee or {}, "work_order": work_order or {}, "process_name": process_name, "remark": remark},
        )
    return int(rid)


def finish_work(record_id: int, end_action: str, remark: str = "", finish_parallel_group: bool = True) -> int:  # type: ignore[override]
    """V212: keep V205 fast SQLite finish, then restore immediate per-row durable save."""
    if not callable(_v212_prev_finish_work):
        raise RuntimeError("finish_work core implementation is unavailable")
    affected_ids = _v212_sqlite_active_group_ids(record_id, finish_parallel_group=finish_parallel_group)
    n = int(_v212_prev_finish_work(record_id, end_action, remark, finish_parallel_group=finish_parallel_group) or 0)
    if affected_ids:
        rows_df = _v212_query_sqlite_rows_by_ids(affected_ids)
        if isinstance(rows_df, pd.DataFrame) and not rows_df.empty:
            _v212_write_row_durable_layers(
                rows_df,
                "finish_work_v212_restore_per_row_save",
                _v212_event_type_for_end_action(end_action),
                extra={"end_action": end_action, "remark": remark, "finish_parallel_group": bool(finish_parallel_group), "affected_ids": affected_ids},
            )
    return int(n)


def audit_v212_per_row_durable_save() -> dict:
    """Diagnostic helper: confirms Start/Finish now calls local per-row durable layers again."""
    return {
        "version": "V212",
        "scope": "services/time_record_service.py backend only",
        "ui_changed": False,
        "css_changed": False,
        "theme_service_changed": False,
        "table_rendering_changed": False,
        "buttons_changed": False,
        "v205_sqlite_fast_transaction_preserved": True,
        "sqlite_id_sequence_guard_against_authority_collision": True,
        "start_finish_immediate_01_02_authority_upsert_restored": True,
        "row_shard_and_event_journal_restored_when_available": bool("_v176_write_durable_layers" in globals() and callable(_v176_write_durable_layers)),
        "foreground_github_upload": False,
        "authority_max_id": _v212_authority_max_id(),
        "reason": "Fix new work record briefly appears then disappears when authority display overwrites SQLite-only row.",
    }

# ================= END V212 RESTORE PER-ROW DURABLE SAVE + AUTHORITY ID SEQUENCE GUARD =================


# ================= V213 FINISH WORK EMPLOYEE-ID AUTHORITY FALLBACK｜2026-05-29 =================
# Problem observed on site:
# - Start Work appears in 今日工時紀錄 / Today Records.
# - The same user selected in 結束目前作業 / Finish Work can still show
#   「此人員目前沒有未結束作業」.
# Root cause class:
# - Today Records display accepts the row by canonical record data.
# - Finish Work used a stricter employee_id + employee_name active lookup.
# - If employee master display name, login display name, or a recovered row's employee_name differs
#   even slightly, the same employee_id can be filtered out.
# Safety rule:
# - Never broaden to all employees.  Fallback is employee_id-only and then re-filters employee_id exactly.
# - This keeps the earlier SSS/SPT243 cross-person guard intact.
try:
    _v213_prev_get_active_records = get_active_records
except Exception:  # pragma: no cover
    _v213_prev_get_active_records = None
try:
    _v213_prev_get_active_record = get_active_record
except Exception:  # pragma: no cover
    _v213_prev_get_active_record = None
try:
    _v213_prev_refresh_active_records_for_employee = refresh_active_records_for_employee
except Exception:  # pragma: no cover
    _v213_prev_refresh_active_records_for_employee = None


def _v213_text(value) -> str:
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    if value is None:
        return ""
    s = str(value).strip()
    if s.lower() in {"none", "nan", "nat", "null", "<na>"}:
        return ""
    return s


def _v213_key(value) -> str:
    return _v213_text(value).casefold()


def _v213_filter_employee_id_exact(df: pd.DataFrame, employee_id: str | None) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    emp = _v213_key(employee_id)
    if not emp:
        return df.reset_index(drop=True)
    out = df.copy()
    if "employee_id" not in out.columns:
        return pd.DataFrame()
    try:
        out = out.loc[out["employee_id"].map(_v213_key) == emp].copy()
    except Exception:
        return pd.DataFrame()
    return out.reset_index(drop=True) if not out.empty else pd.DataFrame()


def _v213_is_active_frame(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()
    try:
        if "_v206_is_active_df" in globals() and callable(_v206_is_active_df):
            out = out.loc[_v206_is_active_df(out)].copy()
        else:
            end_ts = out.get("end_timestamp", pd.Series([""] * len(out))).map(_v213_key)
            status = out.get("status", pd.Series([""] * len(out))).map(_v213_text)
            out = out.loc[end_ts.isin(["", "none", "nan", "nat", "null"]) & status.isin(["", "作業中"])].copy()
    except Exception:
        pass
    return out.reset_index(drop=True) if not out.empty else pd.DataFrame()


def _v213_sort_active_latest(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()
    try:
        if "id" in out.columns:
            out["_v213_id_sort"] = pd.to_numeric(out["id"], errors="coerce").fillna(0)
            out = out.sort_values("_v213_id_sort", ascending=False, kind="stable").drop(columns=["_v213_id_sort"], errors="ignore")
        elif "start_timestamp" in out.columns:
            out["_v213_start_sort"] = pd.to_datetime(out["start_timestamp"], errors="coerce")
            out = out.sort_values("_v213_start_sort", ascending=False, kind="stable").drop(columns=["_v213_start_sort"], errors="ignore")
    except Exception:
        pass
    return out.reset_index(drop=True)


def _v213_employee_id_only_active_lookup(employee_id: str | None, process_name: str | None = None, start_date: str | None = None) -> pd.DataFrame:
    """Lookup active rows by employee_id only, without widening to another person."""
    emp = _v213_text(employee_id)
    if not emp:
        return pd.DataFrame()
    frames: list[pd.DataFrame] = []
    # 1) SQLite fast path, direct and explicit.  This avoids reusing a strict-name wrapper.
    try:
        if "_v206_sqlite_active_df" in globals() and callable(_v206_sqlite_active_df):
            df_sql = _v206_sqlite_active_df(employee_id=emp, process_name=process_name, start_date=start_date, employee_name=None)
            df_sql = _v213_filter_employee_id_exact(_v213_is_active_frame(df_sql), emp)
            if isinstance(df_sql, pd.DataFrame) and not df_sql.empty:
                frames.append(df_sql)
    except Exception:
        pass
    # 2) 01/02 authority fallback by employee_id only.
    try:
        if "_v206_active_authority_df" in globals() and callable(_v206_active_authority_df):
            df_auth = _v206_active_authority_df(employee_id=emp, process_name=process_name, start_date=start_date, employee_name=None)
            df_auth = _v213_filter_employee_id_exact(_v213_is_active_frame(df_auth), emp)
            if isinstance(df_auth, pd.DataFrame) and not df_auth.empty:
                try:
                    if "_v206_upsert_active_rows_to_sqlite" in globals() and callable(_v206_upsert_active_rows_to_sqlite):
                        _v206_upsert_active_rows_to_sqlite(df_auth, reason="v213_finish_employee_id_only_fallback")
                except Exception:
                    pass
                frames.append(df_auth)
    except Exception:
        pass
    if not frames:
        return pd.DataFrame()
    try:
        merged = pd.concat(frames, ignore_index=True, sort=False)
        # Prefer canonical merge/dedupe when available, but never let it widen employee_id.
        if "_v209_merge_display_frames" in globals() and callable(_v209_merge_display_frames):
            merged = _v209_merge_display_frames(frames[0], pd.concat(frames[1:], ignore_index=True, sort=False) if len(frames) > 1 else pd.DataFrame())
        merged = _v213_filter_employee_id_exact(_v213_is_active_frame(merged), emp)
        return _v213_sort_active_latest(merged)
    except Exception:
        merged = pd.concat(frames, ignore_index=True, sort=False)
        return _v213_sort_active_latest(_v213_filter_employee_id_exact(_v213_is_active_frame(merged), emp))


def get_active_records(employee_id: str | None = None, process_name: str | None = None, start_date: str | None = None, employee_name: str | None = None) -> pd.DataFrame:  # type: ignore[override]
    """V213: strict lookup first; if only the name blocks it, retry by employee_id only."""
    df = pd.DataFrame()
    if callable(_v213_prev_get_active_records):
        try:
            df = _v213_prev_get_active_records(employee_id=employee_id, process_name=process_name, start_date=start_date, employee_name=employee_name)
        except TypeError:
            try:
                df = _v213_prev_get_active_records(employee_id=employee_id)
            except Exception:
                df = pd.DataFrame()
        except Exception:
            df = pd.DataFrame()
    df = _v213_filter_employee_id_exact(_v213_is_active_frame(df), employee_id)
    if isinstance(df, pd.DataFrame) and not df.empty:
        return _v213_sort_active_latest(df)
    # Only when caller supplied a name and strict lookup found nothing, relax name but keep employee_id exact.
    if _v213_text(employee_id) and _v213_text(employee_name):
        fallback = _v213_employee_id_only_active_lookup(employee_id, process_name=process_name, start_date=start_date)
        if isinstance(fallback, pd.DataFrame) and not fallback.empty:
            try:
                _v205_direct_log(
                    "V213_FINISH_ACTIVE_ID_FALLBACK",
                    f"Finish Work active lookup used employee_id-only fallback for {employee_id}; selected name={employee_name}",
                    target_id=",".join([str(x) for x in fallback.get("id", pd.Series([], dtype=str)).tolist()]) if "id" in fallback.columns else "",
                    detail="strict employee_id+employee_name lookup returned zero; employee_id exact fallback returned active rows",
                    level="INFO",
                )
            except Exception:
                pass
            return fallback.reset_index(drop=True)
    return pd.DataFrame()


def get_active_record(employee_id: str, employee_name: str | None = None) -> dict | None:  # type: ignore[override]
    df = get_active_records(employee_id=employee_id, employee_name=employee_name)
    if df is None or getattr(df, "empty", True):
        return None
    try:
        return dict(_v213_sort_active_latest(df).iloc[0].to_dict())
    except Exception:
        return None


def refresh_active_records_for_employee(employee_id: str | None = None, employee_name: str | None = None, *, reason: str = "v213_finish_employee_id_fallback") -> int:  # type: ignore[override]
    df = get_active_records(employee_id=employee_id, employee_name=employee_name)
    return int(len(df)) if isinstance(df, pd.DataFrame) and not df.empty else 0


def audit_v213_finish_work_active_identity_fallback() -> dict:
    return {
        "version": "V213",
        "scope": "services/time_record_service.py backend only",
        "ui_changed": False,
        "css_changed": False,
        "theme_service_changed": False,
        "table_rendering_changed": False,
        "buttons_changed": False,
        "v205_sqlite_fast_transaction_preserved": True,
        "v212_row_durable_save_preserved": True,
        "finish_work_strict_lookup_first": True,
        "fallback_scope": "employee_id_only_exact_match_when_employee_name_blocks_active_row",
        "cross_person_widening": False,
        "reason": "Fix Today Records shows just-started work but Finish Work says no active work due to employee_name mismatch/stale display name.",
    }

# ================= END V213 FINISH WORK EMPLOYEE-ID AUTHORITY FALLBACK =================


# ================= V214 FINISH WORK SAME DISPLAY SOURCE FIX｜2026-05-29 =================
# 目的：把 Finish Work 的 active 查詢改回「與 Today Records / load_records 同一顯示資料源」判斷。
# 背景：V205 之後 active 查詢走多層 SQLite/authority wrapper；現場出現 Today Records 看得到，
#      但 Finish Work 顯示「此人員目前沒有未結束作業」。V214 不再依賴前一層 get_active_records，
#      而是直接從目前已修好的顯示資料源(today_records/load_records)篩選未結束紀錄。
# 限制：不改 UI/CSS/theme/table/buttons；不改 V205 秒級交易；不移除 V212 逐筆權威檔保存鏈。


def _v214_text(value) -> str:
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    if value is None:
        return ""
    text = str(value).strip()
    if text.lower() in {"none", "nan", "nat", "null", "<na>"}:
        return ""
    return text


def _v214_key(value) -> str:
    return _v214_text(value).casefold()


def _v214_blank_like(value) -> bool:
    return _v214_key(value) in {"", "none", "nan", "nat", "null", "<na>"}


def _v214_record_key_employee(row: dict) -> str:
    rk = _v214_text((row or {}).get("record_key") or (row or {}).get("紀錄鍵 / Record Key") or (row or {}).get("Record Key"))
    return rk.split("|", 1)[0].strip() if "|" in rk else ""


def _v214_status_is_active(value) -> bool:
    status = _v214_text(value)
    if not status:
        return True
    # 相容前面版本可能寫入的狀態文字；排除下班/暫停/完工/結束。
    return status in {"作業中", "工作中", "進行中", "未結束", "ACTIVE", "Active", "active"}


def _v214_active_mask(df: pd.DataFrame) -> pd.Series:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.Series(dtype=bool)
    end_ts = df.get("end_timestamp", pd.Series([""] * len(df), index=df.index)).map(_v214_text)
    end_action = df.get("end_action", pd.Series([""] * len(df), index=df.index)).map(_v214_text)
    status = df.get("status", pd.Series([""] * len(df), index=df.index)).map(_v214_text)
    # 以 end_timestamp 為主要判斷；若有 end_action 但 end_timestamp 空白，仍視為已結束，避免誤結束。
    end_blank = end_ts.map(_v214_blank_like)
    action_blank = end_action.map(_v214_blank_like)
    status_active = status.map(_v214_status_is_active)
    return end_blank & action_blank & status_active


def _v214_filter_employee_exact(df: pd.DataFrame, employee_id: str | None = None) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    emp = _v214_key(employee_id)
    if not emp:
        return df.copy().reset_index(drop=True)
    rows = []
    for _, rr in df.iterrows():
        row = rr.to_dict()
        got_id = _v214_key(row.get("employee_id") or row.get("工號 / Employee ID") or row.get("工號") or row.get("Employee ID"))
        rk_emp = _v214_key(_v214_record_key_employee(row))
        # 有正式 employee_id 時必須完全一致；只有舊資料缺 employee_id 時才允許 record_key prefix。
        if got_id:
            if got_id == emp:
                rows.append(row)
        elif rk_emp and rk_emp == emp:
            rows.append(row)
    return pd.DataFrame(rows).reset_index(drop=True) if rows else pd.DataFrame()


def _v214_filter_params(
    df: pd.DataFrame,
    *,
    employee_id: str | None = None,
    process_name: str | None = None,
    start_date: str | None = None,
    employee_name: str | None = None,
    work_order: str | None = None,
) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()
    try:
        out = out.loc[_v214_active_mask(out)].copy()
    except Exception:
        pass
    if out.empty:
        return pd.DataFrame()
    out = _v214_filter_employee_exact(out, employee_id)
    if out.empty:
        return pd.DataFrame()
    try:
        if process_name and "process_name" in out.columns:
            proc = _v214_key(process_name)
            out = out.loc[out["process_name"].map(_v214_key) == proc].copy()
        if work_order and "work_order" in out.columns:
            wo = _v214_key(work_order)
            out = out.loc[out["work_order"].map(_v214_key) == wo].copy()
        if start_date:
            sd = _v214_text(start_date).replace("/", "-")[:10]
            if "start_date" in out.columns:
                out = out.loc[out["start_date"].map(_v214_text).str.replace("/", "-", regex=False).str[:10] == sd].copy()
            elif "start_timestamp" in out.columns:
                out = out.loc[out["start_timestamp"].map(_v214_text).str.replace("/", "-", regex=False).str[:10] == sd].copy()
    except Exception:
        pass
    # employee_name 僅作輔助，不再硬擋；前面 UI/主檔姓名不同時，employee_id 一致即允許結束本人作業。
    return out.reset_index(drop=True) if not out.empty else pd.DataFrame()


def _v214_source_frames_for_active(employee_id: str | None = None) -> list[pd.DataFrame]:
    frames: list[pd.DataFrame] = []
    # 1) 直接使用 01 頁 Today Records 同源資料：使用者能在今日表格看到的 active，Finish Work 必須也看得到。
    try:
        df_today_active = today_records(include_finished=False, unfinished_only=True)
        if isinstance(df_today_active, pd.DataFrame) and not df_today_active.empty:
            frames.append(df_today_active)
    except Exception:
        pass
    # 2) 再用 load_records 補跨日/今日函式日期判斷差異；仍是同一 canonical display source。
    try:
        df_all = load_records(employee_id=employee_id) if employee_id else load_records()
        if isinstance(df_all, pd.DataFrame) and not df_all.empty:
            frames.append(df_all)
    except Exception:
        pass
    # 3) 最後才讀底層 SQLite active，保留 V205 秒級新寫入；不靠前一層 wrapper，避免遞迴/舊過濾條件。
    try:
        if "_v205_query_df" in globals() and callable(_v205_query_df) and "_v205_is_active_sql" in globals():
            sql = "SELECT * FROM time_records WHERE " + _v205_is_active_sql()
            params: list = []
            emp = _v214_text(employee_id)
            if emp:
                sql += " AND employee_id=?"
                params.append(emp)
            sql += " ORDER BY id DESC"
            df_sql = _v205_query_df(sql, tuple(params))
            if isinstance(df_sql, pd.DataFrame) and not df_sql.empty:
                frames.append(df_sql)
    except Exception:
        pass
    # 4) 權威檔 active。呼叫時不傳 employee_name，避免姓名不一致擋掉；後續只以 employee_id 嚴格過濾。
    try:
        if "_v206_active_authority_df" in globals() and callable(_v206_active_authority_df):
            df_auth = _v206_active_authority_df(employee_id=_v214_text(employee_id) or None, employee_name=None)
            if isinstance(df_auth, pd.DataFrame) and not df_auth.empty:
                frames.append(df_auth)
    except Exception:
        pass
    return frames


def _v214_concat_dedupe_sort(frames: list[pd.DataFrame]) -> pd.DataFrame:
    usable = [x.copy() for x in frames if isinstance(x, pd.DataFrame) and not x.empty]
    if not usable:
        return pd.DataFrame()
    try:
        merged = pd.concat(usable, ignore_index=True, sort=False)
    except Exception:
        return usable[0].reset_index(drop=True)
    if merged.empty:
        return pd.DataFrame()
    try:
        if "_v206_normalize_time_records_df" in globals() and callable(_v206_normalize_time_records_df):
            merged = _v206_normalize_time_records_df(merged)
    except Exception:
        pass
    try:
        # 同一筆優先用較新/較完整的來源；key 以 record_key 優先，沒有則 id。
        rk = merged.get("record_key", pd.Series([""] * len(merged))).map(_v214_text)
        rid = merged.get("id", pd.Series([""] * len(merged))).map(_v214_text)
        merged["_v214_dedupe_key"] = rk.where(rk != "", "id:" + rid)
        merged["_v214_id_sort"] = pd.to_numeric(merged.get("id", 0), errors="coerce").fillna(0)
        merged["_v214_updated_sort"] = pd.to_datetime(merged.get("updated_at", ""), errors="coerce")
        merged = merged.sort_values(["_v214_id_sort", "_v214_updated_sort"], ascending=[True, True], kind="stable")
        merged = merged.drop_duplicates("_v214_dedupe_key", keep="last")
        merged = merged.sort_values(["_v214_id_sort", "_v214_updated_sort"], ascending=[False, False], kind="stable")
        merged = merged.drop(columns=[c for c in merged.columns if str(c).startswith("_v214_")], errors="ignore")
    except Exception:
        pass
    return merged.reset_index(drop=True)


def get_active_records(employee_id: str | None = None, process_name: str | None = None, start_date: str | None = None, employee_name: str | None = None) -> pd.DataFrame:  # type: ignore[override]
    """V214: Finish Work active lookup must use the same canonical display source as Today Records.

    employee_name is intentionally not a hard filter.  employee_id remains exact, so this cannot show another person.
    """
    frames = _v214_source_frames_for_active(employee_id=employee_id)
    merged = _v214_concat_dedupe_sort(frames)
    out = _v214_filter_params(
        merged,
        employee_id=employee_id,
        process_name=process_name,
        start_date=start_date,
        employee_name=employee_name,
    )
    if isinstance(out, pd.DataFrame) and not out.empty:
        try:
            if "_v206_upsert_active_rows_to_sqlite" in globals() and callable(_v206_upsert_active_rows_to_sqlite):
                _v206_upsert_active_rows_to_sqlite(out, reason="v214_finish_same_display_source")
        except Exception:
            pass
    return out.reset_index(drop=True) if isinstance(out, pd.DataFrame) and not out.empty else pd.DataFrame()


def get_active_record(employee_id: str, employee_name: str | None = None) -> dict | None:  # type: ignore[override]
    df = get_active_records(employee_id=employee_id, employee_name=employee_name)
    if df is None or getattr(df, "empty", True):
        return None
    try:
        return dict(df.iloc[0].to_dict())
    except Exception:
        return None


def get_active_group(record_id: int) -> pd.DataFrame:  # type: ignore[override]
    rid = int(record_id)
    seed = None
    try:
        all_active = get_active_records()
        if isinstance(all_active, pd.DataFrame) and not all_active.empty and "id" in all_active.columns:
            ids = pd.to_numeric(all_active["id"], errors="coerce")
            hit = all_active.loc[ids == rid].copy()
            if not hit.empty:
                seed = dict(hit.iloc[0].to_dict())
    except Exception:
        seed = None
    if seed is None:
        try:
            all_rows = load_records()
            if isinstance(all_rows, pd.DataFrame) and not all_rows.empty and "id" in all_rows.columns:
                ids = pd.to_numeric(all_rows["id"], errors="coerce")
                hit = all_rows.loc[ids == rid].copy()
                if not hit.empty:
                    seed = dict(hit.iloc[0].to_dict())
        except Exception:
            seed = None
    if not seed:
        return pd.DataFrame()
    return get_active_records(
        employee_id=_v214_text(seed.get("employee_id")),
        process_name=_v214_text(seed.get("process_name")),
        start_date=_v214_text(seed.get("start_date")),
        employee_name=None,
    )


def get_active_same_work(employee_id: str, work_order: str, process_name: str, start_date: str | None = None, employee_name: str | None = None) -> dict | None:  # type: ignore[override]
    df = get_active_records(employee_id=employee_id, process_name=process_name, start_date=start_date, employee_name=employee_name)
    df = _v214_filter_params(df, employee_id=employee_id, process_name=process_name, start_date=start_date, work_order=work_order)
    if df is None or getattr(df, "empty", True):
        return None
    try:
        return dict(df.iloc[0].to_dict())
    except Exception:
        return None


def get_conflicting_active_records(employee_id: str, process_name: str, start_date: str | None = None, employee_name: str | None = None) -> pd.DataFrame:  # type: ignore[override]
    df = get_active_records(employee_id=employee_id, employee_name=employee_name)
    if df is None or getattr(df, "empty", True):
        return pd.DataFrame()
    out = df.copy()
    try:
        proc = _v214_key(process_name)
        sd = _v214_text(start_date or (_v205_today() if "_v205_today" in globals() else today_text())).replace("/", "-")[:10]
        if "process_name" in out.columns:
            proc_series = out["process_name"].map(_v214_key)
        else:
            proc_series = pd.Series([""] * len(out), index=out.index)
        if "start_date" in out.columns:
            date_series = out["start_date"].map(_v214_text).str.replace("/", "-", regex=False).str[:10]
        elif "start_timestamp" in out.columns:
            date_series = out["start_timestamp"].map(_v214_text).str.replace("/", "-", regex=False).str[:10]
        else:
            date_series = pd.Series([""] * len(out), index=out.index)
        # 與 V205 舊邏輯一致：同人員 active 中，工段不同或日期不同才是衝突。
        out = out.loc[(proc_series != proc) | (date_series != sd)].copy()
    except Exception:
        pass
    return out.reset_index(drop=True) if isinstance(out, pd.DataFrame) and not out.empty else pd.DataFrame()


def refresh_active_records_for_employee(employee_id: str | None = None, employee_name: str | None = None, *, reason: str = "v214_finish_same_display_source") -> int:  # type: ignore[override]
    df = get_active_records(employee_id=employee_id, employee_name=employee_name)
    try:
        n = int(len(df)) if isinstance(df, pd.DataFrame) and not df.empty else 0
        if n:
            try:
                _v205_direct_log(
                    "V214_FINISH_ACTIVE_SOURCE_OK",
                    f"Finish Work 使用 Today Records/load_records 同源資料找到 {n} 筆未結束作業。",
                    target_id=str(employee_id or ""),
                    detail=str(reason or ""),
                    level="INFO",
                )
            except Exception:
                pass
        return n
    except Exception:
        return 0


def audit_v214_finish_same_display_source_fix() -> dict:
    return {
        "version": "V214",
        "scope": "services/time_record_service.py backend active-query override only",
        "ui_changed": False,
        "css_changed": False,
        "theme_service_changed": False,
        "table_rendering_changed": False,
        "buttons_changed": False,
        "v205_sqlite_fast_transaction_preserved": True,
        "v212_row_durable_save_preserved": True,
        "finish_work_active_source": "same canonical display source as Today Records and load_records",
        "employee_safety": "employee_id exact match required; employee_name no longer blocks same employee",
        "reason": "Today Records can show the just-started row while the previous active wrapper chain returns none.",
    }

# ================= END V214 FINISH WORK SAME DISPLAY SOURCE FIX =================

# ================= V220 01 FRONTEND OPERATION ISOLATION PHASE 1｜2026-05-29 =================
# 目的：保留 V214 讀寫正確、V212 逐筆權威檔保存、Finish Work 與 Today Records 同源判斷，
#      但把 01. 工時紀錄前台常用查詢隔離到本機前台快取，避免每次 Streamlit rerun
#      都重掃 01/02 權威檔造成顯示變慢。
# 限制：不改 UI/CSS/theme/table/buttons；不回退到 SQLite-only；權威檔仍是最終真實來源。
try:
    _v220_prev_today_records = today_records
except Exception:  # pragma: no cover
    _v220_prev_today_records = None
try:
    _v220_prev_get_active_records = get_active_records
except Exception:  # pragma: no cover
    _v220_prev_get_active_records = None
try:
    _v220_prev_get_active_record = get_active_record
except Exception:  # pragma: no cover
    _v220_prev_get_active_record = None
try:
    _v220_prev_get_active_group = get_active_group
except Exception:  # pragma: no cover
    _v220_prev_get_active_group = None
try:
    _v220_prev_start_work = start_work
except Exception:  # pragma: no cover
    _v220_prev_start_work = None
try:
    _v220_prev_finish_work = finish_work
except Exception:  # pragma: no cover
    _v220_prev_finish_work = None

import json as _v220_json
import time as _v220_time
from pathlib import Path as _v220_Path

_V220_VERSION = "V220_FRONTEND_OPERATION_ISOLATION_PHASE1"
try:
    _V220_PROJECT_ROOT = _v220_Path(__file__).resolve().parents[1]
except Exception:  # pragma: no cover
    _V220_PROJECT_ROOT = _v220_Path(".").resolve()
_V220_CACHE_DIR = _V220_PROJECT_ROOT / "data" / "persistent_state" / "frontend_cache"
_V220_TODAY_CACHE = _V220_CACHE_DIR / "01_today_records_cache.json"
_V220_ACTIVE_CACHE = _V220_CACHE_DIR / "01_active_records_index.json"
_V220_META_CACHE = _V220_CACHE_DIR / "01_cache_meta.json"
_V220_CACHE_TTL_SECONDS = 300.0  # 低頻校正：5 分鐘內不反覆重建權威檔快取。
_V220_FINISHED_STATUS = {
    "下班", "暫停", "完工", "已結束", "結束", "完成",
    "off_duty", "paused", "finished", "end", "ended", "complete", "completed",
}


def _v220_text(value) -> str:
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    if value is None:
        return ""
    return str(value).strip()


def _v220_norm_date(value) -> str:
    text = _v220_text(value).replace("/", "-")
    if not text:
        return ""
    if " " in text:
        text = text.split(" ", 1)[0]
    if "T" in text:
        text = text.split("T", 1)[0]
    return text[:10]


def _v220_today() -> str:
    try:
        if "_v205_today" in globals() and callable(_v205_today):
            return _v220_norm_date(_v205_today())
    except Exception:
        pass
    try:
        return _v220_norm_date(today_text())
    except Exception:
        return datetime.now().strftime("%Y-%m-%d")


def _v220_row_date(row: dict) -> str:
    d = _v220_norm_date(row.get("start_date"))
    if d:
        return d
    return _v220_norm_date(row.get("start_timestamp"))


def _v220_record_key(row: dict) -> str:
    rk = _v220_text(row.get("record_key"))
    if rk:
        return "rk:" + rk
    rid = _v220_text(row.get("id"))
    if rid:
        return "id:" + rid
    # 極端 fallback：避免無 key 資料互相覆蓋。
    return "raw:" + "|".join([
        _v220_text(row.get("employee_id")),
        _v220_text(row.get("work_order")),
        _v220_text(row.get("process_name")),
        _v220_text(row.get("start_timestamp")),
    ])


def _v220_is_active_row(row: dict) -> bool:
    if not isinstance(row, dict):
        return False
    end_ts = _v220_text(row.get("end_timestamp"))
    if end_ts:
        return False
    status = _v220_text(row.get("status")).lower()
    if status and status in _V220_FINISHED_STATUS:
        return False
    end_action = _v220_text(row.get("end_action")).lower()
    if end_action and end_action in _V220_FINISHED_STATUS:
        return False
    return True


def _v220_sanitize_value(value):
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    if isinstance(value, (datetime, date)):
        if isinstance(value, datetime):
            return value.strftime("%Y-%m-%d %H:%M:%S")
        return value.strftime("%Y-%m-%d")
    try:
        # pandas Timestamp / numpy scalar 等轉成可 JSON 化。
        if hasattr(value, "item"):
            value = value.item()
    except Exception:
        pass
    if isinstance(value, (int, float, str, bool)) or value is None:
        return value
    return str(value)


def _v220_df_to_records(df: pd.DataFrame) -> list[dict]:
    if not isinstance(df, pd.DataFrame) or df.empty:
        return []
    try:
        tmp = df.copy()
        tmp = tmp.drop(columns=[c for c in tmp.columns if str(c).startswith("_v")], errors="ignore")
        rows = tmp.to_dict(orient="records")
    except Exception:
        return []
    out: list[dict] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        clean = {str(k): _v220_sanitize_value(v) for k, v in row.items()}
        out.append(clean)
    return out


def _v220_records_to_df(records: list[dict]) -> pd.DataFrame:
    if not records:
        return pd.DataFrame()
    try:
        df = pd.DataFrame(records)
        if "_v206_normalize_time_records_df" in globals() and callable(_v206_normalize_time_records_df):
            df = _v206_normalize_time_records_df(df)
        return df.reset_index(drop=True)
    except Exception:
        return pd.DataFrame(records)


def _v220_safe_read_json(path: _v220_Path, default):
    try:
        if not path.exists():
            return default
        text = path.read_text(encoding="utf-8")
        if not text.strip():
            return default
        return _v220_json.loads(text)
    except Exception:
        return default


def _v220_safe_write_json(path: _v220_Path, value) -> None:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        tmp = path.with_suffix(path.suffix + ".tmp")
        tmp.write_text(_v220_json.dumps(value, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
        tmp.replace(path)
    except Exception as exc:
        try:
            if "_v205_direct_log" in globals() and callable(_v205_direct_log):
                _v205_direct_log("V220_CACHE_WRITE_WARN", f"V220 前台快取寫入失敗：{exc}", level="WARN")
        except Exception:
            pass


def _v220_read_meta() -> dict:
    meta = _v220_safe_read_json(_V220_META_CACHE, {})
    return meta if isinstance(meta, dict) else {}


def _v220_write_meta(today_rows: int, active_rows: int, reason: str = "") -> None:
    meta = {
        "cache_version": _V220_VERSION,
        "cache_date": _v220_today(),
        "last_rebuild_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "last_rebuild_epoch": _v220_time.time(),
        "today_rows": int(today_rows or 0),
        "active_rows": int(active_rows or 0),
        "reason": str(reason or ""),
    }
    _v220_safe_write_json(_V220_META_CACHE, meta)


def _v220_cache_valid() -> bool:
    meta = _v220_read_meta()
    if meta.get("cache_version") != _V220_VERSION:
        return False
    if _v220_norm_date(meta.get("cache_date")) != _v220_today():
        return False
    if not _V220_TODAY_CACHE.exists() or not _V220_ACTIVE_CACHE.exists():
        return False
    # 避免每次互動都做權威檔健康檢查；快取由 start/finish 單筆同步維持。
    try:
        epoch = float(meta.get("last_rebuild_epoch") or 0)
        if epoch > 0 and (_v220_time.time() - epoch) < _V220_CACHE_TTL_SECONDS:
            return True
    except Exception:
        pass
    return True


def _v220_sort_records(records: list[dict]) -> list[dict]:
    def _sort_key(row: dict):
        try:
            rid = int(float(row.get("id") or 0))
        except Exception:
            rid = 0
        return (rid, _v220_text(row.get("updated_at")), _v220_text(row.get("start_timestamp")))
    try:
        return sorted(records, key=_sort_key, reverse=True)
    except Exception:
        return records


def _v220_dedupe_records(records: list[dict]) -> list[dict]:
    if not records:
        return []
    by_key: dict[str, dict] = {}
    for row in records:
        if not isinstance(row, dict):
            continue
        by_key[_v220_record_key(row)] = row
    return _v220_sort_records(list(by_key.values()))


def _v220_filter_records_df(
    df: pd.DataFrame,
    *,
    employee_id: str | None = None,
    process_name: str | None = None,
    start_date: str | None = None,
    employee_name: str | None = None,
    work_order: str | None = None,
    active_only: bool = False,
) -> pd.DataFrame:
    if not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()
    try:
        if active_only:
            mask = out.apply(lambda r: _v220_is_active_row(dict(r)), axis=1)
            out = out.loc[mask].copy()
        emp = _v220_text(employee_id)
        if emp and "employee_id" in out.columns:
            out = out.loc[out["employee_id"].map(_v220_text) == emp].copy()
        # employee_name 只在沒有 employee_id 時才當作主要條件；避免姓名顯示差異擋住同一工號。
        name = _v220_text(employee_name)
        if name and not emp and "employee_name" in out.columns:
            out = out.loc[out["employee_name"].map(_v220_text) == name].copy()
        proc = _v220_text(process_name)
        if proc and "process_name" in out.columns:
            out = out.loc[out["process_name"].map(_v220_text) == proc].copy()
        wo = _v220_text(work_order)
        if wo and "work_order" in out.columns:
            out = out.loc[out["work_order"].map(_v220_text) == wo].copy()
        sd = _v220_norm_date(start_date)
        if sd:
            if "start_date" in out.columns:
                out = out.loc[out["start_date"].map(_v220_norm_date) == sd].copy()
            elif "start_timestamp" in out.columns:
                out = out.loc[out["start_timestamp"].map(_v220_norm_date) == sd].copy()
        if not out.empty and "id" in out.columns:
            out["_v220_id_sort"] = pd.to_numeric(out["id"], errors="coerce").fillna(0)
            out = out.sort_values("_v220_id_sort", ascending=False, kind="stable").drop(columns=["_v220_id_sort"], errors="ignore")
    except Exception:
        pass
    return out.reset_index(drop=True) if isinstance(out, pd.DataFrame) and not out.empty else pd.DataFrame()


def _v220_rebuild_front_cache(reason: str = "v220_rebuild") -> None:
    today_df = pd.DataFrame()
    active_df = pd.DataFrame()
    try:
        if callable(_v220_prev_today_records):
            today_df = _v220_prev_today_records(include_finished=True, unfinished_only=False)
    except Exception:
        today_df = pd.DataFrame()
    try:
        if callable(_v220_prev_get_active_records):
            active_df = _v220_prev_get_active_records(employee_id=None, employee_name=None)
    except Exception:
        active_df = pd.DataFrame()
    today_records_list = _v220_dedupe_records(_v220_df_to_records(today_df))
    active_records_list = _v220_dedupe_records([r for r in _v220_df_to_records(active_df) if _v220_is_active_row(r)])
    _v220_safe_write_json(_V220_TODAY_CACHE, today_records_list)
    _v220_safe_write_json(_V220_ACTIVE_CACHE, active_records_list)
    _v220_write_meta(len(today_records_list), len(active_records_list), reason=reason)
    try:
        if "_v205_direct_log" in globals() and callable(_v205_direct_log):
            _v205_direct_log(
                "V220_FRONT_CACHE_REBUILD",
                f"V220 前台快取已重建：Today Records {len(today_records_list)} 筆、Active Index {len(active_records_list)} 筆。",
                detail=str(reason or ""),
                level="INFO",
            )
    except Exception:
        pass


def _v220_get_today_cache_df(force_rebuild: bool = False, reason: str = "v220_today_cache") -> pd.DataFrame:
    if force_rebuild or not _v220_cache_valid():
        _v220_rebuild_front_cache(reason=reason)
    records = _v220_safe_read_json(_V220_TODAY_CACHE, [])
    if not isinstance(records, list):
        records = []
    return _v220_records_to_df(records)


def _v220_get_active_cache_df(force_rebuild: bool = False, reason: str = "v220_active_cache") -> pd.DataFrame:
    if force_rebuild or not _v220_cache_valid():
        _v220_rebuild_front_cache(reason=reason)
    records = _v220_safe_read_json(_V220_ACTIVE_CACHE, [])
    if not isinstance(records, list):
        records = []
    df = _v220_records_to_df(records)
    if isinstance(df, pd.DataFrame) and not df.empty:
        df = _v220_filter_records_df(df, active_only=True)
    return df


def _v220_upsert_cache_row(row: dict, reason: str = "") -> None:
    if not isinstance(row, dict) or not row:
        return
    key = _v220_record_key(row)
    # Today Records 快取只收今日資料；跨日 active 仍會保留在 active index。
    if _v220_row_date(row) == _v220_today():
        today_rows = _v220_safe_read_json(_V220_TODAY_CACHE, [])
        if not isinstance(today_rows, list):
            today_rows = []
        replaced = False
        for i, old in enumerate(today_rows):
            if isinstance(old, dict) and _v220_record_key(old) == key:
                today_rows[i] = row
                replaced = True
                break
        if not replaced:
            today_rows.append(row)
        today_rows = _v220_dedupe_records(today_rows)
        _v220_safe_write_json(_V220_TODAY_CACHE, today_rows)
    active_rows = _v220_safe_read_json(_V220_ACTIVE_CACHE, [])
    if not isinstance(active_rows, list):
        active_rows = []
    # 先移除同 key，再視狀態決定是否加入，避免已結束資料復活。
    active_rows = [r for r in active_rows if not (isinstance(r, dict) and _v220_record_key(r) == key)]
    if _v220_is_active_row(row):
        active_rows.append(row)
    active_rows = _v220_dedupe_records(active_rows)
    _v220_safe_write_json(_V220_ACTIVE_CACHE, active_rows)
    _v220_write_meta(
        len(_v220_safe_read_json(_V220_TODAY_CACHE, []) or []),
        len(active_rows),
        reason=reason or "v220_upsert_cache_row",
    )


def _v220_remove_active_keys(keys: set[str], reason: str = "") -> None:
    if not keys:
        return
    active_rows = _v220_safe_read_json(_V220_ACTIVE_CACHE, [])
    if not isinstance(active_rows, list):
        active_rows = []
    active_rows = [r for r in active_rows if not (isinstance(r, dict) and _v220_record_key(r) in keys)]
    _v220_safe_write_json(_V220_ACTIVE_CACHE, _v220_dedupe_records(active_rows))
    _v220_write_meta(
        len(_v220_safe_read_json(_V220_TODAY_CACHE, []) or []),
        len(active_rows),
        reason=reason or "v220_remove_active_keys",
    )


def _v220_find_record_by_id(record_id: int) -> dict | None:
    rid = _v220_text(record_id)
    if not rid:
        return None
    # 1) SQLite 直接按 id 查，成本最低。
    try:
        if "_v205_query_df" in globals() and callable(_v205_query_df):
            df = _v205_query_df("SELECT * FROM time_records WHERE id=? LIMIT 1", (int(float(rid)),))
            if isinstance(df, pd.DataFrame) and not df.empty:
                return dict(df.iloc[0].to_dict())
    except Exception:
        pass
    try:
        df = query_df("SELECT * FROM time_records WHERE id=? LIMIT 1", (int(float(rid)),))
        if isinstance(df, pd.DataFrame) and not df.empty:
            return dict(df.iloc[0].to_dict())
    except Exception:
        pass
    # 2) 只在 SQLite 找不到時才讀權威檔，且只在開始/結束操作後使用，不會每次前台互動掃描。
    try:
        if "_v208_authority_records_df" in globals() and callable(_v208_authority_records_df):
            auth = _v208_authority_records_df()
            if isinstance(auth, pd.DataFrame) and not auth.empty and "id" in auth.columns:
                ids = pd.to_numeric(auth["id"], errors="coerce")
                hit = auth.loc[ids == int(float(rid))].copy()
                if not hit.empty:
                    return dict(hit.iloc[0].to_dict())
    except Exception:
        pass
    return None


def _v220_group_rows_from_cache(record_id: int) -> pd.DataFrame:
    active = _v220_get_active_cache_df(reason="v220_group_rows_before_finish")
    if not isinstance(active, pd.DataFrame) or active.empty or "id" not in active.columns:
        return pd.DataFrame()
    try:
        ids = pd.to_numeric(active["id"], errors="coerce")
        seed_df = active.loc[ids == int(record_id)].copy()
        if seed_df.empty:
            return pd.DataFrame()
        seed = dict(seed_df.iloc[0].to_dict())
        return _v220_filter_records_df(
            active,
            employee_id=_v220_text(seed.get("employee_id")),
            process_name=_v220_text(seed.get("process_name")),
            start_date=_v220_row_date(seed),
            active_only=True,
        )
    except Exception:
        return pd.DataFrame()


def today_records(include_finished: bool = True, unfinished_only: bool = False) -> pd.DataFrame:  # type: ignore[override]
    """V220: 01 Today Records uses frontend isolated cache; authority is rebuilt only when cache is missing/invalid."""
    df = _v220_get_today_cache_df(reason="v220_today_records")
    if not isinstance(df, pd.DataFrame) or df.empty:
        # 安全 fallback：快取重建仍失敗時，回到 V214 正確來源，避免 No data。
        try:
            if callable(_v220_prev_today_records):
                return _v220_prev_today_records(include_finished=include_finished, unfinished_only=unfinished_only)
        except Exception:
            pass
        return pd.DataFrame()
    if unfinished_only or not include_finished:
        df = _v220_filter_records_df(df, active_only=True)
    return df.reset_index(drop=True) if isinstance(df, pd.DataFrame) and not df.empty else pd.DataFrame()


def get_active_records(employee_id: str | None = None, process_name: str | None = None, start_date: str | None = None, employee_name: str | None = None) -> pd.DataFrame:  # type: ignore[override]
    """V220: Finish Work reads the same frontend cache/index as Today Records, then falls back to V214 only if needed."""
    active = _v220_get_active_cache_df(reason="v220_get_active_records")
    out = _v220_filter_records_df(
        active,
        employee_id=employee_id,
        process_name=process_name,
        start_date=start_date,
        employee_name=employee_name,
        active_only=True,
    )
    if isinstance(out, pd.DataFrame) and not out.empty:
        return out.reset_index(drop=True)
    # 補查 Today cache：避免 active index 檔案損壞但 Today Records 還有未結束資料。
    today_df = _v220_get_today_cache_df(reason="v220_get_active_records_today_fallback")
    out = _v220_filter_records_df(
        today_df,
        employee_id=employee_id,
        process_name=process_name,
        start_date=start_date,
        employee_name=employee_name,
        active_only=True,
    )
    if isinstance(out, pd.DataFrame) and not out.empty:
        for row in _v220_df_to_records(out):
            _v220_upsert_cache_row(row, reason="v220_active_index_repair_from_today_cache")
        return out.reset_index(drop=True)
    # 最後才回到 V214 正確來源，並把查到的 active 回補到前台快取。
    try:
        if callable(_v220_prev_get_active_records):
            out = _v220_prev_get_active_records(employee_id=employee_id, process_name=process_name, start_date=start_date, employee_name=None)
            out = _v220_filter_records_df(out, employee_id=employee_id, process_name=process_name, start_date=start_date, employee_name=employee_name, active_only=True)
            if isinstance(out, pd.DataFrame) and not out.empty:
                for row in _v220_df_to_records(out):
                    _v220_upsert_cache_row(row, reason="v220_active_fallback_backfill")
                return out.reset_index(drop=True)
    except Exception:
        pass
    return pd.DataFrame()


def get_active_record(employee_id: str, employee_name: str | None = None) -> dict | None:  # type: ignore[override]
    df = get_active_records(employee_id=employee_id, employee_name=employee_name)
    if not isinstance(df, pd.DataFrame) or df.empty:
        return None
    try:
        return dict(df.iloc[0].to_dict())
    except Exception:
        return None


def get_active_group(record_id: int) -> pd.DataFrame:  # type: ignore[override]
    df = _v220_group_rows_from_cache(int(record_id))
    if isinstance(df, pd.DataFrame) and not df.empty:
        return df.reset_index(drop=True)
    try:
        if callable(_v220_prev_get_active_group):
            df = _v220_prev_get_active_group(record_id)
            if isinstance(df, pd.DataFrame) and not df.empty:
                for row in _v220_df_to_records(df):
                    _v220_upsert_cache_row(row, reason="v220_group_fallback_backfill")
                return df.reset_index(drop=True)
    except Exception:
        pass
    return pd.DataFrame()


def refresh_active_records_for_employee(employee_id: str | None = None, employee_name: str | None = None, *, reason: str = "v220_frontend_operation_isolation") -> int:  # type: ignore[override]
    df = get_active_records(employee_id=employee_id, employee_name=employee_name)
    return int(len(df)) if isinstance(df, pd.DataFrame) and not df.empty else 0


def start_work(employee: dict, work_order: dict, process_name: str, remark: str = "", auto_pause_old: bool = True) -> int:  # type: ignore[override]
    """V220: keep the V214/V212 correct durable write path, then update 01 frontend cache by single-row upsert."""
    if not callable(_v220_prev_start_work):
        raise RuntimeError("start_work base function is unavailable")
    rid = _v220_prev_start_work(employee, work_order, process_name, remark=remark, auto_pause_old=auto_pause_old)
    try:
        row = _v220_find_record_by_id(int(rid))
        if row:
            _v220_upsert_cache_row(row, reason="v220_start_work_single_row_cache_update")
        else:
            # 找不到單筆時只讓下一次前台讀取重建，不阻擋現場作業。
            _V220_META_CACHE.unlink(missing_ok=True)
    except Exception as exc:
        try:
            if "_v205_direct_log" in globals() and callable(_v205_direct_log):
                _v205_direct_log("V220_START_CACHE_WARN", f"開始作業後更新前台快取失敗：{exc}", target_id=str(rid), level="WARN")
        except Exception:
            pass
    return rid


def finish_work(record_id: int, end_action: str, remark: str = "", finish_parallel_group: bool = True) -> int:  # type: ignore[override]
    """V220: keep the V214/V212 correct durable finish path, then update Today cache and active index by affected ids."""
    if not callable(_v220_prev_finish_work):
        raise RuntimeError("finish_work base function is unavailable")
    affected_ids: set[int] = set()
    affected_keys: set[str] = set()
    seed_row: dict | None = None
    try:
        group_df = _v220_group_rows_from_cache(int(record_id)) if finish_parallel_group else pd.DataFrame()
        if isinstance(group_df, pd.DataFrame) and not group_df.empty:
            for row in _v220_df_to_records(group_df):
                try:
                    affected_ids.add(int(float(row.get("id"))))
                except Exception:
                    pass
                affected_keys.add(_v220_record_key(row))
            seed_row = dict(group_df.iloc[0].to_dict())
        else:
            row = _v220_find_record_by_id(int(record_id))
            if row:
                seed_row = row
                affected_keys.add(_v220_record_key(row))
            affected_ids.add(int(record_id))
    except Exception:
        affected_ids.add(int(record_id))
    result = _v220_prev_finish_work(record_id, end_action, remark=remark, finish_parallel_group=finish_parallel_group)
    try:
        # 先用受影響 id 更新 Today cache；已結束資料會自動從 active index 移除。
        for gid in sorted(affected_ids):
            row = _v220_find_record_by_id(int(gid))
            if row:
                affected_keys.add(_v220_record_key(row))
                _v220_upsert_cache_row(row, reason="v220_finish_work_single_row_cache_update")
        # 若是群組結束，但某些 group row 沒查到，至少移除原 active key，避免 Finish Work 看到舊 active。
        _v220_remove_active_keys(affected_keys, reason="v220_finish_work_remove_finished_active")
        # 保險：同人同工段同日期群組全部移除 active；Today cache 狀態仍以查到的 rows 更新。
        if seed_row:
            active_df = _v220_get_active_cache_df(reason="v220_finish_group_cleanup")
            same_group = _v220_filter_records_df(
                active_df,
                employee_id=_v220_text(seed_row.get("employee_id")),
                process_name=_v220_text(seed_row.get("process_name")),
                start_date=_v220_row_date(seed_row),
                active_only=True,
            )
            if isinstance(same_group, pd.DataFrame) and not same_group.empty:
                keys = {_v220_record_key(r) for r in _v220_df_to_records(same_group)}
                _v220_remove_active_keys(keys, reason="v220_finish_group_cleanup_remove")
    except Exception as exc:
        try:
            if "_v205_direct_log" in globals() and callable(_v205_direct_log):
                _v205_direct_log("V220_FINISH_CACHE_WARN", f"結束作業後更新前台快取失敗：{exc}", target_id=str(record_id), level="WARN")
        except Exception:
            pass
    return result


def audit_v220_frontend_operation_isolation() -> dict:
    meta = _v220_read_meta()
    today_df = _v220_get_today_cache_df(reason="v220_audit_today")
    active_df = _v220_get_active_cache_df(reason="v220_audit_active")
    return {
        "version": "V220",
        "scope": "01 工時紀錄前台操作隔離第一階段；services/time_record_service.py only",
        "ui_changed": False,
        "css_changed": False,
        "theme_service_changed": False,
        "table_rendering_changed": False,
        "buttons_changed": False,
        "authority_write_preserved": True,
        "v212_row_durable_save_preserved": True,
        "finish_work_same_source_preserved": True,
        "today_records_source": "frontend cache, rebuilt directly from local 01/02 authority JSON only when missing/invalid",
        "finish_work_source": "active frontend index, fallback to today cache, then V214 correct source",
        "cache_dir": str(_V220_CACHE_DIR),
        "cache_meta": meta,
        "today_cache_rows": int(len(today_df)) if isinstance(today_df, pd.DataFrame) else 0,
        "active_cache_rows": int(len(active_df)) if isinstance(active_df, pd.DataFrame) else 0,
        "employee_safety": "employee_id exact match required; employee_name does not block same employee_id",
    }

# ================= END V220 01 FRONTEND OPERATION ISOLATION PHASE 1 =================

# ================= V220 DIRECT AUTHORITY REBUILD GUARD｜2026-05-29 =================
# 修正：V220 快取首次重建不可再呼叫較慢的 V214 display wrapper，改為直接讀本機權威 JSON。

def _v220_direct_authority_records() -> list[dict]:
    rows: list[dict] = []
    for module_key in ("01_time_records", "02_history"):
        path = _V220_PROJECT_ROOT / "data" / "permanent_store" / "modules" / module_key / "records.json"
        data = _v220_safe_read_json(path, {})
        try:
            part = data.get("tables", {}).get("time_records", []) if isinstance(data, dict) else []
            if isinstance(part, list):
                rows.extend([r for r in part if isinstance(r, dict)])
        except Exception:
            pass
    return _v220_dedupe_records(rows)


def _v220_direct_authority_records_df() -> pd.DataFrame:
    return _v220_records_to_df(_v220_direct_authority_records())


def _v220_rebuild_front_cache(reason: str = "v220_rebuild") -> None:  # type: ignore[override]
    """V220 guarded rebuild: direct local authority JSON read, no slow display wrapper scan."""
    all_rows = _v220_direct_authority_records()
    today = _v220_today()
    today_records_list = _v220_dedupe_records([r for r in all_rows if _v220_row_date(r) == today])
    active_records_list = _v220_dedupe_records([r for r in all_rows if _v220_is_active_row(r)])
    _v220_safe_write_json(_V220_TODAY_CACHE, today_records_list)
    _v220_safe_write_json(_V220_ACTIVE_CACHE, active_records_list)
    _v220_write_meta(len(today_records_list), len(active_records_list), reason=reason + "|direct_authority_json")
    try:
        if "_v205_direct_log" in globals() and callable(_v205_direct_log):
            _v205_direct_log(
                "V220_FRONT_CACHE_REBUILD_DIRECT",
                f"V220 前台快取已用權威 JSON 直接重建：Today Records {len(today_records_list)} 筆、Active Index {len(active_records_list)} 筆。",
                detail=str(reason or ""),
                level="INFO",
            )
    except Exception:
        pass

# ================= END V220 DIRECT AUTHORITY REBUILD GUARD =================


# ================= V221 SQLITE TABLE GUARD FOR FRONTEND ISOLATION｜2026-05-29 =================
# 修正：V220 第一階段保留了 V212/V205 快速前景交易，但在部分部署環境中
# data/permanent_store/database/spt_time_tracking.db 可能只有權限/登入表，尚未建立 time_records。
# 這會造成按「開始作業」時 SQLite insert / duplicate check 直接噴出：no such table: time_records。
# V221 只補後端保護：開始/結束前確保 SQLite cache table 存在；必要時把該筆/該群組
# 從前台快取或 01/02 權威檔回填到 SQLite，再交給 V220/V212 的正確讀寫鏈處理。
# 不改 UI/CSS/theme/table/buttons；不回退 SQLite-only；權威檔仍是最終真實來源。
try:
    _v221_prev_start_work = start_work
except Exception:  # pragma: no cover
    _v221_prev_start_work = None
try:
    _v221_prev_finish_work = finish_work
except Exception:  # pragma: no cover
    _v221_prev_finish_work = None
try:
    _v221_prev_get_active_records = get_active_records
except Exception:  # pragma: no cover
    _v221_prev_get_active_records = None
try:
    _v221_prev_today_records = today_records
except Exception:  # pragma: no cover
    _v221_prev_today_records = None


def _v221_log(event: str, message: str, *, detail: str = "", target_id: str = "", level: str = "INFO") -> None:
    try:
        if "_v205_direct_log" in globals() and callable(_v205_direct_log):
            _v205_direct_log(event, message, target_id=target_id, detail=detail, level=level)
    except TypeError:
        try:
            _v205_direct_log(event, message, target_id, detail=detail, level=level)  # type: ignore[misc]
        except Exception:
            pass
    except Exception:
        pass


def _v221_ensure_time_records_table(reason: str = "v221") -> bool:
    """Ensure SQLite time_records exists before V205/V212 fast transaction code touches it."""
    ok = False
    try:
        if "_v208_ensure_time_records_table" in globals() and callable(_v208_ensure_time_records_table):
            _v208_ensure_time_records_table()
            ok = True
    except Exception as exc:
        _v221_log("V221_SQLITE_TABLE_GUARD_WARN", f"V221 建立 time_records 快取表失敗：{exc}", detail=reason, level="WARN")
    if ok:
        return True
    # 極端 fallback：若 V208 helper 不可用，直接建立最小相容 schema。
    try:
        with _v205_conn() as conn:  # type: ignore[name-defined]
            conn.execute("""
            CREATE TABLE IF NOT EXISTS time_records (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                record_key TEXT UNIQUE,
                status TEXT,
                work_order TEXT,
                part_no TEXT,
                type_name TEXT,
                process_name TEXT,
                employee_id TEXT,
                employee_name TEXT,
                start_action TEXT,
                start_timestamp TEXT,
                end_action TEXT,
                end_timestamp TEXT,
                remark TEXT,
                start_date TEXT,
                start_time TEXT,
                end_date TEXT,
                end_time TEXT,
                work_hours REAL DEFAULT 0,
                assembly_location TEXT,
                group_key TEXT,
                is_group_work INTEGER DEFAULT 0,
                source TEXT DEFAULT 'streamlit',
                created_at TEXT,
                updated_at TEXT
            )
            """)
            conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_time_records_record_key_v221 ON time_records(record_key)")
            conn.commit()
        return True
    except Exception as exc:
        _v221_log("V221_SQLITE_TABLE_GUARD_FAIL", f"V221 無法建立 time_records 快取表：{exc}", detail=reason, level="ERROR")
        return False


def _v221_sqlite_has_record(record_id: int) -> bool:
    try:
        _v221_ensure_time_records_table("has_record")
        with _v205_conn() as conn:  # type: ignore[name-defined]
            row = conn.execute("SELECT 1 FROM time_records WHERE id=? LIMIT 1", (int(record_id),)).fetchone()
        return bool(row)
    except Exception:
        return False


def _v221_authority_df() -> pd.DataFrame:
    try:
        if "_v220_direct_authority_records_df" in globals() and callable(_v220_direct_authority_records_df):
            df = _v220_direct_authority_records_df()
            return df if isinstance(df, pd.DataFrame) else pd.DataFrame()
    except Exception:
        pass
    try:
        if "_v208_authority_records_df" in globals() and callable(_v208_authority_records_df):
            df = _v208_authority_records_df()
            return df if isinstance(df, pd.DataFrame) else pd.DataFrame()
    except Exception:
        pass
    return pd.DataFrame()


def _v221_rows_by_ids_from_cache_or_authority(ids) -> pd.DataFrame:
    clean: list[int] = []
    for x in ids or []:
        try:
            v = int(float(x))
            if v not in clean:
                clean.append(v)
        except Exception:
            pass
    if not clean:
        return pd.DataFrame()
    frames: list[pd.DataFrame] = []
    try:
        active_df = _v220_get_active_cache_df(reason="v221_rows_by_ids_active_cache") if "_v220_get_active_cache_df" in globals() else pd.DataFrame()
        if isinstance(active_df, pd.DataFrame) and not active_df.empty and "id" in active_df.columns:
            ids_series = pd.to_numeric(active_df["id"], errors="coerce")
            frames.append(active_df.loc[ids_series.isin(clean)].copy())
    except Exception:
        pass
    try:
        today_df = _v220_get_today_cache_df(reason="v221_rows_by_ids_today_cache") if "_v220_get_today_cache_df" in globals() else pd.DataFrame()
        if isinstance(today_df, pd.DataFrame) and not today_df.empty and "id" in today_df.columns:
            ids_series = pd.to_numeric(today_df["id"], errors="coerce")
            frames.append(today_df.loc[ids_series.isin(clean)].copy())
    except Exception:
        pass
    try:
        auth_df = _v221_authority_df()
        if isinstance(auth_df, pd.DataFrame) and not auth_df.empty and "id" in auth_df.columns:
            ids_series = pd.to_numeric(auth_df["id"], errors="coerce")
            frames.append(auth_df.loc[ids_series.isin(clean)].copy())
    except Exception:
        pass
    frames = [f for f in frames if isinstance(f, pd.DataFrame) and not f.empty]
    if not frames:
        return pd.DataFrame()
    try:
        out = pd.concat(frames, ignore_index=True, sort=False)
        if "_v206_normalize_time_records_df" in globals() and callable(_v206_normalize_time_records_df):
            out = _v206_normalize_time_records_df(out)
        if "id" in out.columns:
            out["_v221_id"] = pd.to_numeric(out["id"], errors="coerce")
            out = out.loc[out["_v221_id"].isin(clean)].copy()
        # keep latest duplicate by record key/id
        if "_v220_dedupe_records" in globals() and callable(_v220_dedupe_records) and "_v220_df_to_records" in globals() and callable(_v220_df_to_records):
            rows = _v220_dedupe_records(_v220_df_to_records(out))
            out = _v220_records_to_df(rows) if "_v220_records_to_df" in globals() else pd.DataFrame(rows)
        out = out.drop(columns=[c for c in out.columns if str(c).startswith("_v221_")], errors="ignore")
        return out.reset_index(drop=True)
    except Exception:
        return pd.DataFrame()


def _v221_hydrate_sqlite_rows(df: pd.DataFrame, reason: str = "v221_hydrate") -> int:
    if not isinstance(df, pd.DataFrame) or df.empty:
        return 0
    try:
        _v221_ensure_time_records_table(reason)
        if "_v208_upsert_records_to_sqlite" in globals() and callable(_v208_upsert_records_to_sqlite):
            return int(_v208_upsert_records_to_sqlite(df, reason=reason) or 0)
    except Exception as exc:
        _v221_log("V221_SQLITE_HYDRATE_WARN", f"V221 回填 SQLite 快取失敗：{exc}", detail=reason, level="WARN")
    return 0


def _v221_hydrate_record_for_finish(record_id: int, finish_parallel_group: bool = True, reason: str = "v221_before_finish") -> int:
    """Before V212/V205 finish, ensure the selected active row (and same group if known) exists in SQLite."""
    try:
        rid = int(float(record_id))
    except Exception:
        return 0
    ids: set[int] = {rid}
    try:
        if finish_parallel_group and "_v220_group_rows_from_cache" in globals() and callable(_v220_group_rows_from_cache):
            group_df = _v220_group_rows_from_cache(rid)
            if isinstance(group_df, pd.DataFrame) and not group_df.empty and "id" in group_df.columns:
                for x in pd.to_numeric(group_df["id"], errors="coerce").dropna().tolist():
                    try:
                        ids.add(int(x))
                    except Exception:
                        pass
    except Exception:
        pass
    missing = [x for x in ids if not _v221_sqlite_has_record(x)]
    if not missing:
        return 0
    rows = _v221_rows_by_ids_from_cache_or_authority(missing)
    count = _v221_hydrate_sqlite_rows(rows, reason=reason)
    if count:
        _v221_log("V221_SQLITE_HYDRATE_FOR_FINISH", f"V221 結束前已回填 SQLite time_records {count} 筆。", target_id=",".join(map(str, missing)), detail=reason, level="INFO")
    return int(count or 0)


def _v221_is_no_such_time_records_error(exc: Exception) -> bool:
    text = str(exc or "").lower()
    return "no such table" in text and "time_records" in text


def start_work(employee: dict, work_order: dict, process_name: str, remark: str = "", auto_pause_old: bool = True) -> int:  # type: ignore[override]
    """V221: keep V220/V214/V212 correct chain, but ensure SQLite time_records table before Start Work."""
    if not callable(_v221_prev_start_work):
        raise RuntimeError("start_work base function is unavailable")
    _v221_ensure_time_records_table("start_work_v221_before_base")
    try:
        return int(_v221_prev_start_work(employee, work_order, process_name, remark=remark, auto_pause_old=auto_pause_old) or 0)
    except Exception as exc:
        # Cold deployments may hit no-such-table before all nested wrappers have initialized. Create table once and retry.
        if _v221_is_no_such_time_records_error(exc):
            _v221_ensure_time_records_table("start_work_v221_retry_after_no_such_table")
            _v221_log("V221_SQLITE_TABLE_RETRY", "V221 偵測到 no such table: time_records，已建立快取表並重試開始作業。", detail=str(exc), level="WARN")
            return int(_v221_prev_start_work(employee, work_order, process_name, remark=remark, auto_pause_old=auto_pause_old) or 0)
        raise


def finish_work(record_id: int, end_action: str, remark: str = "", finish_parallel_group: bool = True) -> int:  # type: ignore[override]
    """V221: keep V220/V214/V212 finish chain, but hydrate selected authority/cache row into SQLite first when needed."""
    if not callable(_v221_prev_finish_work):
        raise RuntimeError("finish_work base function is unavailable")
    _v221_ensure_time_records_table("finish_work_v221_before_base")
    _v221_hydrate_record_for_finish(record_id, finish_parallel_group=finish_parallel_group, reason="finish_work_v221_before_base")
    try:
        return int(_v221_prev_finish_work(record_id, end_action, remark=remark, finish_parallel_group=finish_parallel_group) or 0)
    except Exception as exc:
        if _v221_is_no_such_time_records_error(exc):
            _v221_ensure_time_records_table("finish_work_v221_retry_after_no_such_table")
            _v221_hydrate_record_for_finish(record_id, finish_parallel_group=finish_parallel_group, reason="finish_work_v221_retry_after_no_such_table")
            _v221_log("V221_SQLITE_TABLE_RETRY", "V221 偵測到 no such table: time_records，已建立快取表並重試結束作業。", target_id=str(record_id), detail=str(exc), level="WARN")
            return int(_v221_prev_finish_work(record_id, end_action, remark=remark, finish_parallel_group=finish_parallel_group) or 0)
        raise


def audit_v221_sqlite_table_guard() -> dict:
    ok = _v221_ensure_time_records_table("audit_v221")
    exists = False
    count = 0
    try:
        with _v205_conn() as conn:  # type: ignore[name-defined]
            exists = bool(conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='time_records'").fetchone())
            if exists:
                count = int(conn.execute("SELECT COUNT(*) FROM time_records").fetchone()[0])
    except Exception:
        pass
    return {
        "version": "V221",
        "scope": "SQLite time_records table guard for V220 frontend operation isolation",
        "ui_changed": False,
        "css_changed": False,
        "theme_service_changed": False,
        "authority_write_preserved": True,
        "frontend_cache_preserved": True,
        "sqlite_table_guard_ok": bool(ok),
        "sqlite_time_records_table_exists": bool(exists),
        "sqlite_time_records_count": int(count),
        "fixes": "prevents no such table: time_records on Start Work / Finish Work after cold deploy or empty SQLite cache",
    }

