def delete_time_records_v178b_strict(record_ids: list[int], reason: str = "02 歷史紀錄嚴格刪除", editor_df=None) -> dict:  # type: ignore[override]
    ids = sorted({i for i in (_v223_int(x) for x in (record_ids or [])) if i is not None})
